class Solution:
    def minimizeStringValue(self, s: str) -> str:
        count = [0] * 26  # Frequency count of characters
        res = list(s)
        # First pass: count existing characters
        for ch in s:
            if ch != '?':
                count[ord(ch) - ord('a')] += 1

        # Second pass: replace '?' with the least frequent character
        # and lexicographically smallest in case of tie
        for i in range(len(res)):
            if res[i] == '?':
                # Find the character with minimum frequency
                min_freq = float('inf')
                min_char = 'z'
                for c in range(26):
                    if count[c] < min_freq or (count[c] == min_freq and chr(ord('a') + c) < min_char):
                        min_freq = count[c]
                        min_char = chr(ord('a') + c)
                res[i] = min_char
                count[ord(min_char) - ord('a')] += 1

        return ''.join(res)
